	`CREATE INDEX IF NOT EXISTS "UrlClicks_ip_address_idx" ON "UrlClicks" ("ip_address")`,

	// Grant the application role access to all objects created above.
	// The DO block is conditional so that the migration succeeds in dev/test
	// environments where the 'linkshortener' role does not exist.
	// ALTER DEFAULT PRIVILEGES ensures any future migration SQL applied as
	// the postgres superuser also automatically grants access to the app role.
	`DO $$
BEGIN
  IF EXISTS (SELECT FROM pg_roles WHERE rolname = 'linkshortener') THEN
    GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO linkshortener;
    GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO linkshortener;
    ALTER DEFAULT PRIVILEGES FOR ROLE postgres IN SCHEMA public
      GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO linkshortener;
    ALTER DEFAULT PRIVILEGES FOR ROLE postgres IN SCHEMA public
      GRANT USAGE, SELECT ON SEQUENCES TO linkshortener;
  END IF;
END $$`,
}

